//       - Based on Voronoi IQ (https://www.shadertoy.com/view/MslGD8)
//       - Hash functions without trigonometry from (https://www.shadertoy.com/view/4djSRW)
// =========================================================================

#define CELL_GRID_SIZE 6
#define CELL_ANIMATION_PERIOD 6.

#define LAYERS 6
#define LAYER_INTENSITY_INCREASE 0.6
#define LAYER_SCALE_INCREASE 2.0

#define CONTRAST_INTENSITY 0.35

#define PI2 6.2832


struct sVoronoi {
    float distance;
    vec2 id;
};

struct GradientKey {
    float luma;
    vec3 color;
};


float hash21(vec2 p)
{
	vec3 p3  = fract(vec3(p.xyx) * .1031);
    p3 += dot(p3, p3.yzx + 33.33);
    return fract((p3.x + p3.y) * p3.z);
}

vec2 hash22(vec2 p)
{
	vec3 p3 = fract(vec3(p.xyx) * vec3(.1031, .1030, .0973));
    p3 += dot(p3, p3.yzx+33.33);
    return fract((p3.xx+p3.yz)*p3.zy);
}


vec3 saturate(vec3 value) {
    return clamp(value, 0., 1.);
}

float luma(vec3 color) {
    return dot(color, vec3(0.2126, 0.7152, 0.0722));
}

vec3 sCurve(vec3 color, float intensity) {
    vec3 s =  smoothstep(0., 1., color);
    return mix(color, s*s, intensity);
}

vec3 colorPalette(float t, vec3 a, vec3 b, vec3 c, vec3 d) {
    return a + b * cos(PI2 * (c * t + d));
}

vec3 firePalette(float t) {
    vec3 COLOR_A = vec3(0.0, 0.5, 0.9);
    vec3 COLOR_B = vec3(0.7, 0.9, 0.0);
    vec3 COLOR_C = vec3(0.9, 0.4, 0.3);
    vec3 COLOR_D = vec3(0.72, 0.0, 1.0);

    return 1.0 - colorPalette(t, COLOR_A, COLOR_B, COLOR_C, COLOR_D);
}

vec3 gradientMap(vec3 color) {
    float lum = luma(sCurve(color, 0.));
    return firePalette(lum);
}

sVoronoi voronoi(in vec2 uv) {
    // Cell position in grid space
    vec2 cPosGS = floor(uv);

    // Coordinates of the fragment inside the cell space [0 .. 1]
    vec2 cCoord = fract(uv);

    // Start with any number big enough to find the minimum afterwards
    vec3 m = vec3(100.);

    // Check distance of the fragment to each neighboor hash
    // Keep only the closest
    for (int i=-1; i<=1; i++) {
        for (int j=-1; j<=1; j++) {
            // Neighboor offset in grid space 
            vec2 nOffset = vec2(float(i), float(j));

            // Neighboor hash (each cell has a fixed hash)
            vec2 neighboorHash = hash22(cPosGS + nOffset);

            // Use the hash to compute a neighboor positon in grid space
            vec2 neighboorPosGS = 0.5 + 0.5 * sin(PI2 * iTime * neighboorHash / CELL_ANIMATION_PERIOD);

            // Compute the neighbor cell origin in grid space
            vec2 nOrigin = cPosGS + nOffset;

            // Compute the fragment positon in grid space
            vec2 posGS = cPosGS + cCoord;

            // Compute the vector from the fragment to the neighbor hash
            vec2 r = posGS - neighboorPosGS - nOrigin;

            // Compute the length of the vector            
            float d2 = dot(r, r);

            // If the distance is the min, keep distance and neighboor hash
            if (d2 < m.x) {
                m = vec3(d2, neighboorHash);
            }
        }
    }

    // return the distance and a unique id to display unique colors
    return sVoronoi(sqrt(m.x), m.yz);
}

vec3 voronoiLayer(sVoronoi v, float intensity) {
    return intensity * smoothstep(0.0, 1.0, vec3(v.distance)); 
}

void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    // Get uv in Grid Space

    vec3 col = vec3(0.);
    float intensity = 1.0;
    float scale = 1.0;
    for (int i=0; i<LAYERS; i++) {
        vec2 uvGS = float(CELL_GRID_SIZE) * scale * fragCoord.xy / max(iResolution.x, iResolution.y) - (iTime / 10.);

        sVoronoi v = voronoi(uvGS);
        // Compute a radial gradient inside the cell to shad
        col += saturate(voronoiLayer(v, intensity)) / sqrt(float(LAYERS));
        intensity *= LAYER_INTENSITY_INCREASE; 
        scale *= LAYER_SCALE_INCREASE;
    }

    // Output to screen
    fragColor = vec4(sCurve(gradientMap(col), CONTRAST_INTENSITY), 1.);
}
